"use client";

import * as React from "react";
import { useReducedMotion } from "motion/react";

import { cn } from "@/lib/utils";
import { damp, useMediaQuery } from "@/components/experience/experience-runtime";

export type ElasticImageGridItem = { id: string; label: string; content: React.ReactNode; className?: string };
export type ElasticImageGridProps = Omit<React.ComponentProps<"section">, "children"> & {
  label: string;
  items: ElasticImageGridItem[];
  minItemWidth?: number;
  radius?: number;
  maxTravel?: number;
  maxScale?: number;
  maxTilt?: number;
  smoothing?: number;
  gridClassName?: string;
  itemClassName?: string | ((item: ElasticImageGridItem, index: number) => string | undefined);
  header?: React.ReactNode;
};

/** A semantic image grid with a bounded spring field; no cursor replacement and no touch hijacking. */
export function ElasticImageGrid({ className, gridClassName, header, itemClassName, items, label, maxScale = .075, maxTilt = 3.5, maxTravel = 34, minItemWidth = 260, radius = 420, smoothing = 10, onPointerLeave, onPointerMove, ...props }: ElasticImageGridProps) {
  const rootRef = React.useRef<HTMLElement>(null);
  const itemRefs = React.useRef(new Map<string, HTMLElement>());
  const pointerRef = React.useRef({ x: 0, y: 0, active: false });
  const statesRef = React.useRef(new Map<string, { x: number; y: number; scale: number; rotateX: number; rotateY: number }>());
  const reducedMotion = useReducedMotion();
  const coarse = useMediaQuery("(pointer: coarse)");
  const staticMode = Boolean(reducedMotion) || coarse;
  React.useEffect(() => {
    if (staticMode) return;
    const itemElements = itemRefs.current;
    const motionStates = statesRef.current;
    let frame = 0, disposed = false, previous = performance.now();
    const render = (time: number) => {
      if (disposed) return;
      const delta = Math.min(.05, Math.max(.001, (time - previous) / 1000)); previous = time;
      itemElements.forEach((element, id) => {
        const rect = element.getBoundingClientRect();
        const dx = pointerRef.current.x - (rect.left + rect.width / 2), dy = pointerRef.current.y - (rect.top + rect.height / 2);
        const distance = Math.hypot(dx, dy), influence = pointerRef.current.active ? Math.max(0, 1 - distance / radius) : 0;
        const targetX = distance ? (dx / distance) * maxTravel * influence : 0, targetY = distance ? (dy / distance) * maxTravel * influence : 0;
        const state = motionStates.get(id) ?? { x: 0, y: 0, scale: 1, rotateX: 0, rotateY: 0 };
        state.x = damp(state.x, targetX, smoothing, delta); state.y = damp(state.y, targetY, smoothing, delta); state.scale = damp(state.scale, 1 + maxScale * influence, smoothing, delta); state.rotateX = damp(state.rotateX, -(dy / Math.max(1, radius)) * maxTilt * influence, smoothing, delta); state.rotateY = damp(state.rotateY, (dx / Math.max(1, radius)) * maxTilt * influence, smoothing, delta);
        motionStates.set(id, state); element.style.transform = `translate3d(${state.x}px,${state.y}px,0) rotateX(${state.rotateX}deg) rotateY(${state.rotateY}deg) scale(${state.scale})`;
      });
      frame = requestAnimationFrame(render);
    };
    frame = requestAnimationFrame(render);
    return () => { disposed = true; cancelAnimationFrame(frame); itemElements.forEach((element) => { element.style.transform = ""; }); motionStates.clear(); };
  }, [maxScale, maxTilt, maxTravel, radius, smoothing, staticMode]);
  const handlePointerMove = (event: React.PointerEvent<HTMLElement>) => { if (event.pointerType !== "touch") pointerRef.current = { x: event.clientX, y: event.clientY, active: true }; onPointerMove?.(event); };
  const handlePointerLeave = (event: React.PointerEvent<HTMLElement>) => { pointerRef.current.active = false; onPointerLeave?.(event); };
  return <section ref={rootRef} aria-label={label} data-elastic-image-grid data-static={staticMode || undefined} className={cn("relative", className)} onPointerMove={handlePointerMove} onPointerLeave={handlePointerLeave} {...props}>{header}<div className={cn("grid gap-4", gridClassName)} style={{ gridTemplateColumns: `repeat(auto-fit,minmax(min(100%,${minItemWidth}px),1fr))` }}>{items.map((item, index) => <article ref={(node) => { if (node) itemRefs.current.set(item.id, node); else itemRefs.current.delete(item.id); }} key={item.id} aria-label={item.label} className={cn("relative transform-gpu overflow-hidden rounded-[2rem] will-change-transform", typeof itemClassName === "function" ? itemClassName(item, index) : itemClassName, item.className)}>{item.content}</article>)}</div></section>;
}

"use client";

import * as React from "react";

const subscribeToHydration = () => () => undefined;

export function useHydrated() {
  return React.useSyncExternalStore(subscribeToHydration, () => true, () => false);
}

export function useMediaQuery(query: string, serverValue = false) {
  const subscribe = React.useCallback(
    (onChange: () => void) => {
      const media = window.matchMedia(query);
      media.addEventListener("change", onChange);
      return () => media.removeEventListener("change", onChange);
    },
    [query],
  );
  const getSnapshot = React.useCallback(() => window.matchMedia(query).matches, [query]);
  return React.useSyncExternalStore(subscribe, getSnapshot, () => serverValue);
}

/**
 * Hydration-safe reduced-motion preference: false on the server and during
 * hydration, then live. Replaces the repeated `mounted && useReducedMotion()`
 * pattern.
 */
export function usePrefersReducedMotion() {
  return useMediaQuery("(prefers-reduced-motion: reduce)");
}

/** True on touch-first devices; use to swap pointer effects for static or rail modes. */
export function useCoarsePointer() {
  return useMediaQuery("(pointer: coarse)");
}

/** True only when a hover-capable precise pointer is present. */
export function useFinePointer() {
  return useMediaQuery("(hover: hover) and (pointer: fine)");
}

export function clamp01(value: number) {
  return Math.min(1, Math.max(0, value));
}

export function mix(from: number, to: number, amount: number) {
  return from + (to - from) * amount;
}

export function damp(current: number, target: number, smoothing: number, deltaSeconds: number) {
  return mix(current, target, 1 - Math.exp(-Math.max(0.01, smoothing) * deltaSeconds));
}

/** Returns the frames sorted by `at`, reusing the input when it is already ordered. */
export function sortKeyframes<T extends { at: number }>(frames: T[]): T[] {
  for (let index = 1; index < frames.length; index += 1) {
    if (frames[index - 1]!.at > frames[index]!.at) {
      return [...frames].sort((left, right) => left.at - right.at);
    }
  }
  return frames;
}

export function resolveKeyframes<T extends { at: number }>(
  frames: T[],
  progress: number,
): { from: T; to: T; mix: number } {
  if (frames.length === 0) throw new Error("Experience keyframes cannot be empty.");
  const sorted = sortKeyframes(frames);
  if (progress <= sorted[0]!.at) return { from: sorted[0]!, to: sorted[0]!, mix: 0 };
  for (let index = 0; index < sorted.length - 1; index += 1) {
    const from = sorted[index]!;
    const to = sorted[index + 1]!;
    if (progress <= to.at) {
      const span = Math.max(0.0001, to.at - from.at);
      return { from, to, mix: clamp01((progress - from.at) / span) };
    }
  }
  const final = sorted.at(-1)!;
  return { from: final, to: final, mix: 0 };
}

export function supportsWebGL() {
  try {
    const canvas = document.createElement("canvas");
    return Boolean(
      canvas.getContext("webgl2", { failIfMajorPerformanceCaveat: true })
      || canvas.getContext("webgl", { failIfMajorPerformanceCaveat: true }),
    );
  } catch {
    return false;
  }
}
